    40→const searchSchema = z.object({
    41→  t: z.string().min(1, "Token is required"),
    42→});
    43→
    44→const createFormSchema = (editAddress: boolean, editPaymentMethod: boolean) => {
    45→  // Countries that require region/state/province - matches AddressFields component
    46→  const countriesRequiringRegion = [
    47→    "US", // United States
    48→    "CA", // Canada
    49→    "AU", // Australia
    50→    "IN", // India
    51→    "BR", // Brazil
    52→    "MX", // Mexico
    53→    "DE", // Germany
    54→    "AR", // Argentina
    55→    "NG", // Nigeria
    56→    "RU", // Russia
    57→    "ID", // Indonesia
    58→    "MY", // Malaysia
    59→    "ZA", // South Africa
    60→    "PH", // Philippines
    61→    "AE", // United Arab Emirates
    62→  ];
    63→
    64→  return (
    65→    z
    66→      .object({
    67→        amount: z
    68→          .number()
    69→          .min(
    70→            1,
    71→            "Amount must be greater than 0. To cancel your commitment, use the link below this form.",
    72→          ),
    73→        line1: z.string(),
    74→        line2: z.string(),
    75→        city: z.string(),
    76→        region: z.string(),
    77→        country: z.string(),
    78→        postalCode: z.string(),
    79→        rawCardNumber: z.string(),
    80→        expiry: z.string(),
    81→        cvv: z.string(),
    82→        accountNumber: z.string(),
    83→        routingNumber: z.string(),
    84→        accountType: z.enum(["personal-checking", "personal-savings"]),
    85→        paymentMethodType: z.enum(["credit_card", "bank_account"]),
    86→      })
    87→      // Address validation
    88→      .refine((data) => !editAddress || !!data.line1, {
    89→        message: "Street address is required",
    90→        path: ["line1"],
    91→      })
    92→      .refine((data) => !editAddress || !!data.city, {
    93→        message: "City is required",
    94→        path: ["city"],
    95→      })
    96→      .refine(
    97→        (data) =>
    98→          !editAddress ||
    99→          !countriesRequiringRegion.includes(data.country) ||
   100→          !!data.region,
   101→        {
   102→          message: "State/Province/Region is required",
   103→          path: ["region"],
   104→        },
   105→      )
   106→      .refine((data) => !editAddress || !!data.postalCode, {
   107→        message: "Postal code is required",
   108→        path: ["postalCode"],
   109→      })
   110→      .refine(
   111→        (data) =>
   112→          !editAddress ||
   113→          !data.postalCode ||
   114→          data.country !== "US" ||
   115→          /^\d{5}$/.test(data.postalCode),
   116→        {
   117→          message: "US postal code must be 5 digits",
   118→          path: ["postalCode"],
   119→        },
   120→      )
   121→      .refine(
   122→        (data) =>
   123→          !editAddress ||
   124→          !data.postalCode ||
   125→          data.country === "US" ||
   126→          (data.postalCode.length >= 3 && data.postalCode.length <= 12),
   127→        {
   128→          message: "Postal code must be 3-12 characters",
   129→          path: ["postalCode"],
   130→        },
   131→      )
   132→      // Credit card validation (only when editing payment method and type is credit_card)
   133→      .refine(
   134→        (data) =>
   135→          !editPaymentMethod ||
   136→          data.paymentMethodType !== "credit_card" ||
   137→          !!data.rawCardNumber,
   138→        {
   139→          message: "Valid card number is required",
   140→          path: ["rawCardNumber"],
   141→        },
   142→      )
   143→      .refine(
   144→        (data) =>
   145→          !editPaymentMethod ||
   146→          data.paymentMethodType !== "credit_card" ||
   147→          !data.rawCardNumber ||
   148→          /^\d{13,19}$/.test(data.rawCardNumber.replace(/\s/g, "")),
   149→        {
   150→          message: "Card number must be 13-19 digits",
   151→          path: ["rawCardNumber"],
   152→        },
   153→      )
   154→      .refine(
   155→        (data) =>
   156→          !editPaymentMethod ||
   157→          data.paymentMethodType !== "credit_card" ||
   158→          !!data.expiry,
   159→        {
   160→          message: "Valid expiration date is required",
   161→          path: ["expiry"],
   162→        },
   163→      )
   164→      .refine(
   165→        (data) =>
   166→          !editPaymentMethod ||
   167→          data.paymentMethodType !== "credit_card" ||
   168→          !data.expiry ||
   169→          /^(0[1-9]|1[0-2])\/(\d{2}|\d{4})$/.test(data.expiry),
   170→        {
   171→          message: "Expiry date must be in MM/YY format",
   172→          path: ["expiry"],
   173→        },
   174→      )
   175→      .refine(
   176→        (data) => {
   177→          if (
   178→            !editPaymentMethod ||
   179→            data.paymentMethodType !== "credit_card" ||
   180→            !data.expiry
   181→          )
   182→            return true;
   183→
   184→          const [month, year] = data.expiry.split("/");
   185→          let fullYear = Number(year);
   186→
   187→          // Convert 2-digit year to 4-digit year
   188→          if (year.length === 2) {
   189→            const currentYear = new Date().getFullYear();
   190→            const currentCentury = Math.floor(currentYear / 100) * 100;
   191→            const twoDigitYear = Number(year);
   192→
   193→            // If the 2-digit year is less than current year's last 2 digits + 10,
   194→            // assume it's in the current century, otherwise previous century
   195→            if (twoDigitYear < (currentYear % 100) + 10) {
   196→              fullYear = currentCentury + twoDigitYear;
   197→            } else {
   198→              fullYear = currentCentury - 100 + twoDigitYear;
   199→            }
   200→          }
   201→
   202→          const expDate = new Date(fullYear, Number(month) - 1);
   203→          const now = new Date();
   204→          now.setDate(1); // Set to first day of current month for comparison
   205→
   206→          return expDate >= now;
   207→        },
   208→        {
   209→          message: "Card has expired",
   210→          path: ["expiry"],
   211→        },
   212→      )
   213→      .refine(
   214→        (data) =>
   215→          !editPaymentMethod ||
   216→          data.paymentMethodType !== "credit_card" ||
   217→          !!data.cvv,
   218→        {
   219→          message: "Valid CVV is required",
   220→          path: ["cvv"],
   221→        },
   222→      )
   223→      .refine(
   224→        (data) => {
   225→          if (
   226→            !editPaymentMethod ||
   227→            data.paymentMethodType !== "credit_card" ||
   228→            !data.cvv
   229→          ) {
   230→            return true;
   231→          }
   232→
   233→          // Strip any non-digit characters before validation
   234→          const cleanCvv = data.cvv.replace(/\D/g, "");
   235→          return /^\d{3,4}$/.test(cleanCvv);
   236→        },
   237→        {
   238→          message: "CVV must be 3 or 4 digits",
   239→          path: ["cvv"],
   240→        },
   241→      )
   242→      // Bank account validation (only when editing payment method and type is bank_account)
   243→      .refine(
   244→        (data) =>
   245→          !editPaymentMethod ||
   246→          data.paymentMethodType !== "bank_account" ||
   247→          (!!data.accountNumber &&
   248→            data.accountNumber.length >= 4 &&
   249→            data.accountNumber.length <= 17),
   250→        {
   251→          message: "Account number must be between 4 and 17 digits",
   252→          path: ["accountNumber"],
   253→        },
   254→      )
   255→      .refine(
   256→        (data) =>
   257→          !editPaymentMethod ||
   258→          data.paymentMethodType !== "bank_account" ||
   259→          !data.accountNumber ||
   260→          /^\d+$/.test(data.accountNumber),
   261→        {
   262→          message: "Account number must contain only digits",
   263→          path: ["accountNumber"],
   264→        },
   265→      )
   266→      .refine(
   267→        (data) =>
   268→          !editPaymentMethod ||
   269→          data.paymentMethodType !== "bank_account" ||
   270→          !data.routingNumber ||
   271→          /^\d{9}$/.test(data.routingNumber),
   272→        {
   273→          message: "Routing number must be exactly 9 digits",
   274→          path: ["routingNumber"],
   275→        },
   276→      )
   277→      .refine(
   278→        (data) =>
   279→          !editPaymentMethod ||
   280→          data.paymentMethodType !== "bank_account" ||
   281→          !!data.accountType,
   282→        {
   283→          message: "Valid account type is required",
   284→          path: ["accountType"],
   285→        },
   286→      )
   287→  );
   288→};
