   290→export const Route = createFileRoute(
   291→  "/token-auth/commitment/$commitmentId/update",
   292→)({
   293→  component: RouteComponent,
   294→  validateSearch: searchSchema,
   295→  loaderDeps: ({ search: { t } }) => ({ t }),
   296→  loader: async ({ params, deps: { t } }) => {
   297→    const commitment = await queryClient.fetchQuery(
   298→      useGetCommitmentQueryOptions({
   299→        commitmentId: params.commitmentId,
   300→        t,
   301→      }),
   302→    );
   303→
   304→    const actionPage = await queryClient.fetchQuery(
   305→      useGetPublicActionPageQueryOptions({
   306→        actionPageSlug: commitment.actionPageSlug,
   307→        accountSlug: commitment.accountSlug,
   308→      }),
   309→    );
   310→
   311→    const account = await queryClient.fetchQuery(
   312→      useGetAccountQueryOptions({
   313→        accountUid: actionPage.account.id || "",
   314→      }),
   315→    );
   316→
   317→    if (commitment.active === false) {
   318→      throw redirect({
   319→        params: { commitmentId: commitment.id },
   320→        search: { t },
   321→        to: "/token-auth/commitment/$commitmentId/reactivate",
   322→      });
   323→    }
   324→
   325→    return {
   326→      account,
   327→      actionPage,
   328→      cancelinkOptions: linkOptions({
   329→        params: { commitmentId: params.commitmentId },
   330→        search: { t },
   331→        to: "/token-auth/commitment/$commitmentId/cancel",
   332→      }),
   333→      successLinkOptions: linkOptions({
   334→        params: { commitmentId: params.commitmentId },
   335→        search: { t },
   336→        to: "/token-auth/commitment/$commitmentId/success",
   337→      }),
   338→      commitment,
   339→      formLayout: computeFormLayout(actionPage),
   340→    };
   341→  },
   342→});
   343→
   344→function RouteComponent() {
   345→  // Generate Kount fraud detection session ID
   346→  const ddcSessionId = useMemo(() => v4().replace(/-/g, ""), []);
   347→
   348→  const { t } = Route.useSearch();
   349→  const {
   350→    account,
   351→    commitment,
   352→    cancelinkOptions,
   353→    successLinkOptions,
   354→    formLayout,
   355→  } = Route.useLoaderData();
   356→
   357→  const [editAddress, setEditAddress] = useState(false);
   358→  const [editPaymentMethod, setEditPaymentMethod] = useState(false);
   359→
   360→  const navigate = useNavigate();
   361→  const { handleApiError, handleError } = useRollbarErrorHandler();
   362→
   363→  const { mutate: updateCommitment } = useUpdateCommitment({
   364→    onError: (error) => {
   365→      const status = "response" in error ? error.response?.status : undefined;
   366→
   367→      // Skip 401 errors (handled by automatic redirect)
   368→      if (status !== 401) {
   369→        // Log all errors including 422 validation errors
   370→        handleApiError(error, {
   371→          action: "update_commitment",
   372→          commitmentId: commitment.id,
   373→          validationError: status === 422,
   374→        });
   375→      }
   376→
   377→      toast.error(error.message || "Unable to update commitment");
   378→    },
   379→    onSuccess: () => {
   380→      // Debug: Log the success to console
   381→      navigate(successLinkOptions);
   382→    },
   383→  });
   384→
   385→  const { mutateAsync: createPaymentMethod } = useCreatePaymentMethod({
   386→    onError: (error) => {
   387→      const status = "response" in error ? error.response?.status : undefined;
   388→
   389→      // Skip 401 errors (handled by automatic redirect)
   390→      if (status !== 401) {
   391→        // Log all errors including 422 validation errors
   392→        handleApiError(error, {
   393→          action: "create_payment_method",
   394→          commitmentId: commitment.id,
   395→          validationError: status === 422,
   396→        });
   397→      }
   398→
   399→      toast.error(error.message || "Unable to create payment method");
   400→    },
   401→  });
   402→
   403→  useEffect(() => {
   404→    const kountConfig = {
   405→      clientID: import.meta.env.VITE_KOUNT_CLIENT_ID,
   406→      environment: import.meta.env.VITE_KOUNT_ENVIRONMENT,
   407→      isSinglePageApp: true,
   408→    };
   409→
   410→    try {
   411→      kountSDK(kountConfig, ddcSessionId);
   412→    } catch (error) {
   413→      // Log Kount SDK initialization failure, but don't block the user
   414→      // The ddcSessionId will still be sent, but won't have fraud detection data
   415→      handleError(error as Error, {
   416→        action: "kount_sdk_initialization",
   417→        commitmentId: commitment.id,
   418→        ddcSessionId,
   419→      });
   420→    }
   421→  }, [ddcSessionId, handleError, commitment.id]);
   422→
   423→  const formSchema = useMemo(() => {
   424→    return createFormSchema(editAddress, editPaymentMethod);
   425→  }, [editAddress, editPaymentMethod]);
   426→
   427→  const Form = useAppForm({
   428→    defaultValues: {
   429→      amount: Number(commitment.totalAmount),
   430→      line1: commitment.addressAttributes?.line1 ?? "",
   431→      line2: commitment.addressAttributes?.line2 ?? "",
   432→      city: commitment.addressAttributes?.city ?? "",
   433→      region: commitment.addressAttributes?.region ?? "",
   434→      country: commitment.addressAttributes?.country ?? "US",
   435→      postalCode: commitment.addressAttributes?.postalCode ?? "",
   436→      rawCardNumber: "",
   437→      expiry: "",
   438→      cvv: "",
   439→      accountNumber: "",
   440→      routingNumber: "",
   441→      accountType: "personal-checking",
   442→      paymentMethodType: "credit_card",
   443→    },
   444→    validators: {
   445→      onBlur: formSchema,
   446→    },
   447→    onSubmit: async (data) => {
   448→      const updateData: Parameters<typeof updateCommitment>[0] = {
   449→        t,
   450→        commitmentId: commitment.id,
   451→        ddc_session_id: ddcSessionId,
   452→        amountAllocationsAttributes: commitment.amountAllocationsAttributes
   453→          ? reallocateAmount(
   454→              data.value.amount,
   455→              commitment.amountAllocationsAttributes,
   456→            )
   457→          : [],
   458→      };
   459→
   460→      const amount =
   461→        commitment.amountAllocationsAttributes?.reduce(
   462→          (acc, curr) => acc + curr.amount,
   463→          0,
   464→        ) ?? 0;
   465→
   466→      if (editAddress) {
   467→        updateData.addressAttributes = {
   468→          id: commitment.addressAttributes?.id ?? "",
   469→          line1: data.value.line1,
   470→          line2: data.value.line2,
   471→          city: data.value.city,
   472→          region: data.value.region,
   473→          postalCode: data.value.postalCode,
   474→          country: data.value.country,
   475→        };
   476→      }
   477→
   478→      if (editPaymentMethod) {
   479→        const paymentMethodAttributes: PaymentMethodAttributes = {
   480→          store: true,
   481→          billingAddressAttributes: {
   482→            addressLine1: data.value.line1,
   483→            addressLine2: data.value.line2,
   484→            city: data.value.city,
   485→            state: data.value.country === "US" ? data.value.region : null,
   486→            postalCode: data.value.postalCode,
   487→            country: data.value.country,
   488→            email: commitment.donorDetailsAttributes?.email ?? null,
   489→            name: `${commitment.donorDetailsAttributes?.firstName} ${commitment.donorDetailsAttributes?.lastName}`,
   490→            phone: commitment.donorDetailsAttributes?.phone ?? null,
   491→          },
   492→        };
   493→        if (data.value.paymentMethodType === "credit_card") {
   494→          const [month, year] = data.value.expiry.split("/");
   495→          let fullYear = Number(year);
   496→
   497→          // Convert 2-digit year to 4-digit year
   498→          if (year.length === 2) {
   499→            const currentYear = new Date().getFullYear();
   500→            const currentCentury = Math.floor(currentYear / 100) * 100;
   501→            const twoDigitYear = Number(year);
   502→
   503→            // If the 2-digit year is less than current year's last 2 digits + 10,
   504→            // assume it's in the current century, otherwise previous century
   505→            if (twoDigitYear < (currentYear % 100) + 10) {
   506→              fullYear = currentCentury + twoDigitYear;
   507→            } else {
   508→              fullYear = currentCentury - 100 + twoDigitYear;
   509→            }
   510→          }
   511→
   512→          paymentMethodAttributes.cardProfileAttributes = {
   513→            cvc: data.value.cvv.replace(/\D/g, ""), // Strip any non-digit characters
   514→            encryptedCardNumber: encrypt(
   515→              data.value.rawCardNumber.replace(/\D/g, ""), // Strip any non-digit characters
   516→            ),
   517→            expMonth: Number(month),
   518→            expYear: fullYear,
   519→          };
   520→        } else {
   521→          paymentMethodAttributes.bankAccountProfileAttributes = {
   522→            accountHolderName: `${commitment.donorDetailsAttributes?.firstName} ${commitment.donorDetailsAttributes?.lastName}`,
   523→            accountHolderType:
   524→              data.value.accountType === "personal-checking" ||
   525→              data.value.accountType === "personal-savings"
   526→                ? "personal"
   527→                : "business",
   528→            accountType:
   529→              data.value.accountType === "personal-checking" ||
   530→              data.value.accountType === "business-checking"
   531→                ? "checking"
   532→                : "savings",
   533→            encryptedAccountNumber: encrypt(
   534→              data.value.accountNumber.replace(/\D/g, ""),
   535→            ),
   536→            routingNumber: data.value.routingNumber,
   537→          };
   538→        }
   539→        const paymentMethod = await createPaymentMethod({
   540→          accountSlug: commitment.accountSlug,
   541→          paymentMethods: paymentMethodAttributes,
   542→          ddc_session_id: ddcSessionId,
   543→          amount,
   544→        });
   545→
   546→        updateData.paymentMethodId = paymentMethod.id;
   547→      }
   548→
